write_emacs_theme() {
  prepare_target "$current_dir/emacs-theme.el"
  cat > "$current_dir/emacs-theme.el" <<EOF
;;; Generated by theme-select from $style. -*- lexical-binding: t; -*-

(setq sk/theme
      '((foreground . "$(hex '.[$style].semantic.foreground')")
        (foreground-alt . "$(hex '.[$style].palette.fgAlt')")
        (background . "$(hex '.[$style].semantic.background')")
        (background-alt . "$(hex '.[$style].palette.base1')")
        (surface . "$(hex '.[$style].semantic.surface')")
        (surface-strong . "$(hex '.[$style].semantic.surfaceStrong')")
        (border . "$(hex '.[$style].semantic.border')")
        (border-active . "$(hex '.[$style].semantic.borderActive')")
        (accent . "$(hex '.[$style].semantic.accent')")
        (accent-alt . "$(hex '.[$style].semantic.accentAlt')")
        (muted . "$(hex '.[$style].semantic.muted')")
        (success . "$(hex '.[$style].semantic.success')")
        (warning . "$(hex '.[$style].semantic.warning')")
        (danger . "$(hex '.[$style].semantic.danger')")
        (selection-foreground . "$(hex '.[$style].semantic.selectionForeground')")
        (selection-background . "$(hex '.[$style].semantic.selectionBackground')")
        (string . "$(hex '.[$style].editorSyntax.string')")
        (function . "$(hex '.[$style].editorSyntax.function')")
        (keyword . "$(hex '.[$style].editorSyntax.keyword')")
        (number . "$(hex '.[$style].editorSyntax.number')")
        (type . "$(hex '.[$style].editorSyntax.type')")
        (builtin . "$(hex '.[$style].editorSyntax.builtin')")
        (variable . "$(hex '.[$style].editorSyntax.variable')")
        (property . "$(hex '.[$style].editorSyntax.property')")
        (operator . "$(hex '.[$style].editorSyntax.operator')")
        (punctuation . "$(hex '.[$style].editorSyntax.punctuation')")
        (doc . "$(hex '.[$style].editorSyntax.doc')")
        (preprocessor . "$(hex '.[$style].editorSyntax.preprocessor')")
        (comment . "$(hex '.[$style].editorSyntax.comment')")
        (black . "$(hex '.[$style].terminal.black')")
        (red . "$(hex '.[$style].terminal.red')")
        (green . "$(hex '.[$style].terminal.green')")
        (yellow . "$(hex '.[$style].terminal.yellow')")
        (blue . "$(hex '.[$style].terminal.blue')")
        (magenta . "$(hex '.[$style].terminal.magenta')")
        (cyan . "$(hex '.[$style].terminal.cyan')")
        (white . "$(hex '.[$style].terminal.brightWhite')")))
EOF
}
